class Solution:
    def replaceWords(self, dictionary: List[str], sentence: str) -> str:
        trie={}
        for w in dictionary:
            node=trie
            for ch in w: node=node.setdefault(ch,{})
            node["#"]=w
        def prefix(w):
            node=trie
            for ch in w:
                if ch not in node: return w
                node=node[ch]
                if "#" in node: return node["#"]
            return w
        return " ".join(prefix(w) for w in sentence.split())

